import React, { useEffect, useState } from "react";
import { Pie } from "react-chartjs-2";
import { Chart as ChartJS, ArcElement, Tooltip, Legend } from "chart.js";

ChartJS.register(ArcElement, Tooltip, Legend);

const Dashboard = () => {
  const [cumulativeData, setCumulativeData] = useState({});

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("journalEntries")) || [];
    const totals = {};

    stored.forEach((entry) => {
      if (entry.analyzed && entry.analysis) {
        const analysis = parseAnalysisString(entry.analysis);

        for (const [emotion, score] of Object.entries(analysis)) {
          totals[emotion] = (totals[emotion] || 0) + score;
        }
      }
    });

    setCumulativeData(totals);
  }, []);

  // Parses strings like: "disgust (37.6%), anticipation (32.6%), anger (26.5%)"
  const parseAnalysisString = (str) => {
    const result = {};
    const regex = /([a-zA-Z\s]+)\s*\(([\d.]+)%\)/g;
    let match;

    while ((match = regex.exec(str)) !== null) {
      const emotion = match[1].trim().toLowerCase();
      const value = parseFloat(match[2]);
      if (!isNaN(value)) {
        result[emotion] = value;
      }
    }

    return result;
  };

  const labels = Object.keys(cumulativeData);
  const dataValues = Object.values(cumulativeData);

  const chartData = {
    labels,
    datasets: [
      {
        label: "Cumulative Emotion Scores",
        data: dataValues,
        backgroundColor: [
          "#7e5f40",  // --text
          "#d6b98c",  // --secondary-color
          "#7b8b58",  // --button-color
          "#8c6fc3",  // --accent-lavender
          "#f5e6c8",  // --bg-parchment
          "#5a4432",  // --button-border
          "#fdfaf5",  // --flower-white
          "#7a6651",  // --text-light
        ],
        borderColor: "#fff",
        borderWidth: 1
      }
    ]
  };

  return (
    <div className="dashboard-page">
      <h1>Cumulative Emotion Analysis</h1>
      {labels.length > 0 ? (
        <div className="chart-container">
          <Pie data={chartData} />
        </div>
      ) : (
        <p>No analyzed journal data found.</p>
      )}

      <style>{`
        .dashboard-page {
          font-family: 'Cedarville Cursive', cursive;
          padding: 2rem;
          background-color: var(--bg-parchment);
          color: var(--text);
          display: flex;
          flex-direction: column;
          align-items: center;
        }

        .chart-container {
          max-width: 500px;
          width: 100%;
        }

        h1 {
          color: var(--font-text);
          font-size: 2rem;
          margin-bottom: 1.5rem;
        }
      `}</style>
    </div>
  );
};

export default Dashboard;
